#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

class Solution {
public:
    bool solve(vector<int>& nums) {
        for (int i = 0; i < nums.size(); i++) {
            for (int j = 0; j < nums.size() - i - 1; j++) {
                if (nums[j] > nums[j + 1]) {
                    swap(nums[j], nums[j + 1]);
                }
            }
        }
        return true;
    }
};

int main() {
    Solution solution;
    int n;
    cin >> n;
    vector<int> sample_nums(n);
    for (int i = 0; i < n; i++) {
        cin >> sample_nums[i];
    }
    solution.solve(sample_nums);
    for (int num : sample_nums) {
        cout << num << " ";
    }
    return 0;
}
